/**
 * sensory-ui Sound Engine
 *
 * The lowest runtime layer — handles AudioContext lifecycle, buffer decoding/
 * caching, and playback scheduling via the Web Audio API.
 *
 * This module is framework-agnostic (no React dependency). All React-specific
 * wiring lives in provider.tsx and use-play-sound.ts.
 */

let audioContext: AudioContext | null = null;
const bufferCache = new Map<string, AudioBuffer>();

/** Tracks the most recently started playback so rapid re-triggers cancel the
 *  previous sound, preventing overlapping audio when users spam-click. */
let activePlayback: SoundPlayback | null = null;

export function getAudioContext(): AudioContext {
  if (!audioContext) {
    audioContext = new AudioContext();
  }
  return audioContext;
}

// ---------------------------------------------------------------------------
// Sound source types
// ---------------------------------------------------------------------------

/**
 * A synthesizer function that generates sound directly via the Web Audio API.
 * Receives the shared AudioContext and playback options, starts the sound
 * immediately, and returns a SoundPlayback handle.
 *
 * Synthesizers are the preferred approach for built-in sound packs - no
 * decoding step, no base64 bloat, zero network requests.
 */
export type SoundSynthesizer = (
  ctx: AudioContext,
  options: PlaySoundOptions
) => SoundPlayback;

/**
 * A sound source is either:
 * - A `SoundSynthesizer` function (programmatic Web Audio generation)
 * - A `string` (base64 data URI or a URL to a file in public/)
 */
export type SoundSource = SoundSynthesizer | string;

/**
 * Decode a base64 data URI into an AudioBuffer.
 * Used when sounds are embedded as base64-encoded TS modules.
 */
async function decodeBase64DataUri(dataUri: string): Promise<AudioBuffer> {
  const cached = bufferCache.get(dataUri);
  if (cached) return cached;

  const ctx = getAudioContext();
  const base64 = dataUri.split(",")[1];
  if (!base64) throw new Error("[sensory-ui] Invalid data URI");

  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const audioBuffer = await ctx.decodeAudioData(bytes.buffer.slice(0));
  bufferCache.set(dataUri, audioBuffer);
  return audioBuffer;
}

/**
 * Fetch and decode an audio source into an AudioBuffer.
 * Accepts both regular URLs and base64 data URIs.
 * Results are cached by source string so each is decoded only once.
 */
export async function decodeAudioData(source: string): Promise<AudioBuffer> {
  // Handle base64 data URIs directly - no network fetch needed
  if (source.startsWith("data:")) {
    return decodeBase64DataUri(source);
  }

  // Regular URL path (e.g. user override pointing to /sounds/custom/...)
  const cached = bufferCache.get(source);
  if (cached) return cached;

  const ctx = getAudioContext();
  const response = await fetch(source);
  if (!response.ok) {
    throw new Error(`[sensory-ui] Failed to fetch audio: ${response.status} ${response.statusText}`);
  }
  const arrayBuffer = await response.arrayBuffer();
  const audioBuffer = await ctx.decodeAudioData(arrayBuffer);

  bufferCache.set(source, audioBuffer);
  return audioBuffer;
}

export interface PlaySoundOptions {
  /** 0–1. Multiplied with master volume from config. */
  volume?: number;
  /** Default 1.0. Values > 1 speed up, < 1 slow down. */
  playbackRate?: number;
  /** Called when the sound finishes playing naturally. */
  onEnd?: () => void;
}

export interface SoundPlayback {
  stop: () => void;
}

export async function playSound(
  source: SoundSource,
  options: PlaySoundOptions = {}
): Promise<SoundPlayback> {
  const { volume = 1, playbackRate = 1, onEnd } = options;

  const ctx = getAudioContext();

  if (ctx.state === "suspended") {
    await ctx.resume();
  }

  // Cancel the previously playing sound to prevent overlapping audio
  // when users spam-click or rapidly trigger interactions.
  if (activePlayback) {
    try { activePlayback.stop(); } catch { /* ok */ }
    activePlayback = null;
  }

  // If the source is a synthesizer function, call it directly - no decoding step.
  if (typeof source === "function") {
    const playback = source(ctx, {
      volume,
      playbackRate,
      onEnd: () => {
        if (activePlayback === playback) activePlayback = null;
        onEnd?.();
      },
    });
    activePlayback = playback;
    return playback;
  }

  const buffer = await decodeAudioData(source);
  const bufferSource = ctx.createBufferSource();
  const gain = ctx.createGain();

  bufferSource.buffer = buffer;
  bufferSource.playbackRate.value = playbackRate;
  gain.gain.value = Math.max(0, Math.min(1, volume));

  bufferSource.connect(gain);
  gain.connect(ctx.destination);

  bufferSource.onended = () => {
    if (activePlayback === playback) activePlayback = null;
    onEnd?.();
  };

  bufferSource.start(0);

  const playback: SoundPlayback = {
    stop: () => {
      try {
        bufferSource.stop();
      } catch {
        // No-op if already stopped.
      }
    },
  };

  activePlayback = playback;
  return playback;
}

export function clearBufferCache(): void {
  bufferCache.clear();
}

export async function closeAudioContext(): Promise<void> {
  if (audioContext) {
    await audioContext.close();
    audioContext = null;
  }
}

"use client";

import * as React from "react";
import {
  closeAudioContext,
  playSound as enginePlaySound,
  type PlaySoundOptions,
  type SoundPlayback,
} from "./engine";
import {
  defaultConfig,
  mergeConfig,
  resolveRole,
  type SensoryUIConfig,
} from "./config";
import type { SoundRole } from "./sound-roles";

// ---------------------------------------------------------------------------
// Context shape
// ---------------------------------------------------------------------------

export interface SensoryUIContextValue {
  /**
   * Play a sound by its semantic role.
   * Returns a SoundPlayback handle or null if suppressed.
   */
  playSound: (
    role: SoundRole,
    options?: PlaySoundOptions
  ) => Promise<SoundPlayback | null>;
  /** Whether the sound system is globally active. */
  enabled: boolean;
  /** Current master volume (0–1). */
  volume: number;
  /** Whether the user has manually muted all sounds. */
  muted: boolean;
  /** Toggle the mute state programmatically. */
  setMuted: (muted: boolean) => void;
}

const SensoryUIContext = React.createContext<SensoryUIContextValue | null>(
  null
);

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useSensoryUI(): SensoryUIContextValue {
  const ctx = React.useContext(SensoryUIContext);
  if (!ctx) {
    throw new Error(
      "[sensory-ui] useSensoryUI must be called inside <SensoryUIProvider>"
    );
  }
  return ctx;
}

// ---------------------------------------------------------------------------
// Reduced-motion hook
// ---------------------------------------------------------------------------

function useReducedMotion(
  pref: SensoryUIConfig["reducedMotion"]
): boolean {
  const [matches, setMatches] = React.useState(() => {
    if (typeof window === "undefined") return false;
    return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  });

  React.useEffect(() => {
    if (typeof window === "undefined") return;
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    const handler = (e: MediaQueryListEvent) => setMatches(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);

  if (pref === "force-off") return true;
  if (pref === "force-on") return false;
  return matches;
}

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

interface SensoryUIProviderProps {
  children: React.ReactNode;
  /**
   * Optional config overrides merged on top of the defaults in config.ts.
   * Useful for Storybook, tests, or dynamic settings.
   *
   * @example
   * // Disable all sounds in tests
   * <SensoryUIProvider config={{ enabled: false }}>
   */
  config?: Partial<SensoryUIConfig>;
}

export function SensoryUIProvider({
  children,
  config: configOverride,
}: SensoryUIProviderProps) {
  const config = React.useMemo(
    () => mergeConfig(configOverride ?? {}),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [JSON.stringify(configOverride)]
  );

  const [muted, setMuted] = React.useState(false);
  const reducedMotion = useReducedMotion(config.reducedMotion);
  const shouldPlay = config.enabled && !muted && !reducedMotion;

  const playSound = React.useCallback(
    async (
      role: SoundRole,
      options: PlaySoundOptions = {}
    ): Promise<SoundPlayback | null> => {
      if (typeof window === "undefined") return null;
      if (!shouldPlay) return null;

      const finalVolume = (options.volume ?? 1) * config.volume;

      // Detect raw URLs / data-URIs passed via usePlaySound and bypass
      // role resolution — send them straight to the engine.
      const isRawSource =
        typeof role === "string" &&
        (role.startsWith("/") ||
          role.startsWith("http://") ||
          role.startsWith("https://") ||
          role.startsWith("data:"));

      const source = isRawSource ? role : resolveRole(role, config);
      if (!source) return null;

      try {
        return await enginePlaySound(source, { ...options, volume: finalVolume });
      } catch (err) {
        if (process.env.NODE_ENV === "development") {
          console.warn("[sensory-ui] Failed to play sound:", role, err);
        }
        return null;
      }
    },
    [shouldPlay, config]
  );

  // Clean up the AudioContext on unmount in development to avoid stale state
  // across HMR reloads.
  React.useEffect(() => {
    if (process.env.NODE_ENV !== "development") return;
    return () => {
      void closeAudioContext();
    };
  }, []);

  const value = React.useMemo(
    () => ({
      playSound,
      enabled: shouldPlay,
      volume: config.volume,
      muted,
      setMuted,
    }),
    [playSound, shouldPlay, config.volume, muted]
  );

  return (
    <SensoryUIContext.Provider value={value}>
      {children}
    </SensoryUIContext.Provider>
  );
}

/**
 * sensory-ui Configuration
 *
 * Defines `SensoryUIConfig`, the default config, merge logic, and
 * `resolveRole()` which maps a SoundRole → SoundSource at runtime.
 */

import type { SoundCategory, SoundRole } from "./sound-roles";
import type { SoundSource } from "./engine";
import { packRegistry, type SoundPackName } from "./registry";

export interface SensoryUIConfig {
  /** Global kill-switch. false silences everything. */
  enabled: boolean;
  /** Master volume multiplier. Range: 0–1. */
  volume: number;
  /**
   * Sound pack name. Selects a built-in pack or falls back to "aero".
   *
   * Built-in packs: soft | aero (default) | arcade | organic | glass |
   *                 industrial | minimal | retro | crisp
   *
   * Individual roles can still be overridden via `overrides` regardless
   * of which pack is active.
   */
  theme: SoundPackName | (string & {});
  /** Per-category enable/disable toggles. */
  categories: Record<SoundCategory, boolean>;
  /**
   * Role-level source overrides.
   * Values can be:
   *   - A URL path to a file in public/ (e.g. "/sounds/my-click.mp3")
   *   - A base64 data URI (e.g. "data:audio/mp3;base64,...")
   * These take precedence over the active sound pack.
   */
  overrides: Partial<Record<SoundRole, string>>;
  /**
   * How to respond to prefers-reduced-motion.
   * "inherit"   → respect the OS/browser setting
   * "force-off" → always suppress sounds
   * "force-on"  → always play sounds regardless of user pref
   */
  reducedMotion: "inherit" | "force-off" | "force-on";
}

/**
 * Default config - used when no overrides are provided.
 * Edit sensory.config.js at the project root or pass a `config` prop to
 * <SensoryUIProvider> to customise at runtime.
 */
export const defaultConfig: SensoryUIConfig = {
  enabled: true,
  volume: 0.35,
  theme: "aero",
  categories: {
    interaction: true,
    overlay: true,
    navigation: true,
    notification: true,
    hero: false, // Disabled by default - must be explicitly enabled
  },
  overrides: {},
  reducedMotion: "inherit",
};

export function mergeConfig(
  user: Partial<SensoryUIConfig>
): SensoryUIConfig {
  return {
    ...defaultConfig,
    ...user,
    categories: {
      ...defaultConfig.categories,
      ...(user.categories ?? {}),
    },
    overrides: {
      ...defaultConfig.overrides,
      ...(user.overrides ?? {}),
    },
  };
}

/**
 * Resolve a SoundRole to its audio source.
 *
 * Resolution priority:
 *   1. config.overrides[role]    - user-defined string override (URL or base64)
 *   2. packRegistry[theme][role] - synthesizer from the active sound pack
 *   3. packRegistry.aero[role]   - fallback to "aero" if theme name is unknown
 *   4. null                      - category disabled or role not found
 */
export function resolveRole(
  role: SoundRole,
  config: SensoryUIConfig
): SoundSource | null {
  const category = role.split(".")[0] as SoundCategory;

  if (config.categories[category] === false) return null;

  // User override takes highest priority (always a string/URL)
  const override = config.overrides[role];
  if (override) return override;

  // Look up the active pack, fall back to "aero" if pack name is unknown
  const packName = config.theme as SoundPackName;
  const pack = packRegistry[packName] ?? packRegistry.aero;
  const source = pack[role];

  return source ?? null;
}

/**
 * sensory-ui Sound Roles
 *
 * Defines the 17 semantic sound roles organised into 5 categories.
 * These types are the public contract — every component's `sound` prop
 * accepts a value of type `SoundRole`.
 *
 * Material Design alignment:
 *   interaction.*  → Primary UX sounds   (frequent, subtle, understated)
 *   overlay.*      → Secondary UX sounds  (state changes, less frequent)
 *   navigation.*   → Primary UX sounds   (navigation feedback)
 *   notification.* → Notifications        (attention-directing)
 *   hero.*         → Hero sounds          (celebration, disabled by default)
 */

export type SoundCategory =
  | "interaction"
  | "overlay"
  | "navigation"
  | "notification"
  | "hero";

export type InteractionRole =
  | "interaction.tap"
  | "interaction.subtle"
  | "interaction.toggle"
  | "interaction.confirm";

export type OverlayRole =
  | "overlay.open"
  | "overlay.close"
  | "overlay.expand"
  | "overlay.collapse";

export type NavigationRole =
  | "navigation.forward"
  | "navigation.backward"
  | "navigation.tab";

export type NotificationRole =
  | "notification.info"
  | "notification.success"
  | "notification.warning"
  | "notification.error";

export type HeroRole = "hero.complete" | "hero.milestone";

export type SoundRole =
  | InteractionRole
  | OverlayRole
  | NavigationRole
  | NotificationRole
  | HeroRole;

export const ALL_SOUND_ROLES: SoundRole[] = [
  "interaction.tap",
  "interaction.subtle",
  "interaction.toggle",
  "interaction.confirm",
  "overlay.open",
  "overlay.close",
  "overlay.expand",
  "overlay.collapse",
  "navigation.forward",
  "navigation.backward",
  "navigation.tab",
  "notification.info",
  "notification.success",
  "notification.warning",
  "notification.error",
  "hero.complete",
  "hero.milestone",
];

export function parseRole(role: SoundRole): {
  category: SoundCategory;
  name: string;
} {
  const [category, name] = role.split(".") as [SoundCategory, string];
  return { category, name };
}

import type { SoundRole } from "./sound-roles";
import type { SoundSource } from "./engine";
import {
  softPack,
  aeroPack,
  arcadePack,
  organicPack,
  glassPack,
  industrialPack,
  minimalPack,
  retroPack,
  crispPack,
  type SoundPackName,
} from "../sounds/packs";

// Re-export so consumers can import SoundPackName from this module
export type { SoundPackName };

/**
 * A complete mapping of every SoundRole to a SoundSource for one pack.
 * SoundSource is either a SoundSynthesizer function (preferred) or a
 * base64 data URI / public-path string (for custom user overrides).
 */
export type SoundPack = Record<SoundRole, SoundSource>;

// ---------------------------------------------------------------------------
// Pack registry - maps pack name → full SoundPack
// ---------------------------------------------------------------------------

/**
 * All built-in sound packs, keyed by their `SoundPackName`.
 *
 * The engine uses this via `config.theme` to resolve a role to
 * its audio source before playback.
 */
export const packRegistry: Record<SoundPackName, SoundPack> = {
  soft: softPack,
  aero: aeroPack,
  arcade: arcadePack,
  organic: organicPack,
  glass: glassPack,
  industrial: industrialPack,
  minimal: minimalPack,
  retro: retroPack,
  crisp: crispPack,
};

/**
 * Default sound pack name.
 * "aero" is the default - balanced, pleasant, professional.
 */
export const DEFAULT_PACK: SoundPackName = "aero";

/**
 * Backwards-compat alias: the default pack's role → source mapping.
 */
export const roleRegistry: SoundPack = aeroPack;

"use client";

import * as React from "react";

import { useSensoryUI } from "./provider";
import type { SoundRole } from "./sound-roles";

export interface UsePlaySoundOptions {
  /**
   * SoundRole (e.g. "activation.primary") or an absolute URL to a custom
   * audio file (e.g. "/sounds/custom/beep.mp3").
   */
  sound: SoundRole | (string & {});
  /**
   * Volume multiplier for this specific sound (0–1).
   * Stacks multiplicatively with the provider-level volume.
   */
  volume?: number;
}

export interface UsePlaySoundReturn {
  /** Imperatively trigger the sound. Safe to call during render - it is
   *  memoised and will no-op if the provider is disabled or muted. */
  play: () => void;
  /** Whether audio is currently enabled (provider not disabled, not muted,
   *  not suppressed by prefers-reduced-motion). */
  enabled: boolean;
}

/**
 * `usePlaySound` - low-level hook for imperative sound playback.
 *
 * Use this when you need to trigger a sound outside a sensory-ui component,
 * for example in a custom component or an event handler.
 *
 * @example
 * ```tsx
 * const { play } = usePlaySound({ sound: "notifications.success" });
 * // ...
 * <button onClick={play}>Save</button>
 * ```
 */
export function usePlaySound({
  sound,
  volume,
}: UsePlaySoundOptions): UsePlaySoundReturn {
  const { playSound, enabled } = useSensoryUI();

  const play = React.useCallback(() => {
    void playSound(sound as SoundRole, { volume });
  }, [playSound, sound, volume]);

  return { play, enabled };
}

/**
 * sensory-ui Sounds Module
 *
 * This module provides all sound-related exports for sensory-ui:
 * - Core synthesis engine (tunes, instruments, factory)
 * - Generated sound packs (soft, aero, arcade, organic, glass, etc.)
 */

// Core sound synthesis system
export * from "./core";

// All 9 instrument-based sound packs
export * from "./packs";

/**
 * Generated Sound Packs
 *
 * 9 distinct sound packs generated using the instrument-based system.
 * Each pack uses a different instrument configuration to create
 * unique sonic characters from the same base tunes.
 *
 * Hero sounds are custom-crafted for each pack to match their character.
 */

import type { SoundRole } from "../config/sound-roles";
import type { SoundSynthesizer, PlaySoundOptions, SoundPlayback } from "../config/engine";
import {
  SOFT_INSTRUMENT,
  AERO_INSTRUMENT,
  ARCADE_INSTRUMENT,
  ORGANIC_INSTRUMENT,
  GLASS_INSTRUMENT,
  INDUSTRIAL_INSTRUMENT,
  MINIMAL_INSTRUMENT,
  RETRO_INSTRUMENT,
  CRISP_INSTRUMENT,
} from "./core/instruments";
import { generateSoundPack } from "./core/pack-generator";

// ---------------------------------------------------------------------------
// Sound Pack Type
// ---------------------------------------------------------------------------

export type GeneratedSoundPack = Record<SoundRole, SoundSynthesizer>;

// ---------------------------------------------------------------------------
// Note frequencies for hero sounds
// ---------------------------------------------------------------------------
const NOTES = {
  C3: 130.81, D3: 146.83, E3: 164.81, F3: 174.61, G3: 196.0, A3: 220.0, B3: 246.94,
  C4: 261.63, D4: 293.66, E4: 329.63, F4: 349.23, G4: 392.0, A4: 440.0, B4: 493.88,
  C5: 523.25, D5: 587.33, E5: 659.25, F5: 698.46, G5: 783.99, A5: 880.0, B5: 987.77,
  C6: 1046.5, D6: 1174.66, E6: 1318.51, G6: 1567.98,
};

// ---------------------------------------------------------------------------
// Soft Pack - Warm, gentle hero sounds
// ---------------------------------------------------------------------------

const softHeroComplete: SoundSynthesizer = (ctx: AudioContext, opts: PlaySoundOptions): SoundPlayback => {
  const t = ctx.currentTime;
  const vol = (opts.volume ?? 1) * 0.65;
  // Lullaby resolution: descend from E→C then rise to G→C5
  const notes = [NOTES.E4, NOTES.C4, NOTES.G4, NOTES.C5];
  const oscs: OscillatorNode[] = [];
  const gains: GainNode[] = [];

  notes.forEach((freq, i) => {
    const noteStart = t + i * 0.22;
    const isLast = i === notes.length - 1;
    const ringDur = isLast ? 0.8 : 0.15;
    const decay = noteStart + 0.2 + ringDur;

    const osc = ctx.createOscillator();
    osc.type = "sine";
    osc.frequency.value = freq * 0.8;

    const g = ctx.createGain();
    g.gain.setValueAtTime(0.001, noteStart);
    g.gain.linearRampToValueAtTime(vol, noteStart + 0.05);
    g.gain.exponentialRampToValueAtTime(0.001, decay);

    osc.connect(g);
    g.connect(ctx.destination);
    oscs.push(osc);
    gains.push(g);

    osc.start(noteStart);
    osc.stop(decay + 0.05);

    if (isLast) {
      osc.onended = () => {
        oscs.forEach(o => { try { o.disconnect(); } catch {} });
        gains.forEach(g => { try { g.disconnect(); } catch {} });
        opts.onEnd?.();
      };
    }
  });

  return { stop: () => oscs.forEach(o => { try { o.stop(); } catch {} }) };
};

const softHeroMilestone: SoundSynthesizer = (ctx: AudioContext, opts: PlaySoundOptions): SoundPlayback => {
  const t = ctx.currentTime;
  const vol = (opts.volume ?? 1) * 0.55;
  // Gentle descending major 3rd
  const notes = [NOTES.E4, NOTES.C4];
  const oscs: OscillatorNode[] = [];

  notes.forEach((freq, i) => {
    const noteStart = t + i * 0.25;
    const isLast = i === notes.length - 1;
    const decay = noteStart + (isLast ? 0.6 : 0.2);

    const osc = ctx.createOscillator();
    osc.type = "sine";
    osc.frequency.value = freq * 0.8;

    const g = ctx.createGain();
    g.gain.setValueAtTime(0.001, noteStart);
    g.gain.linearRampToValueAtTime(vol, noteStart + 0.04);
    g.gain.exponentialRampToValueAtTime(0.001, decay);

    osc.connect(g);
    g.connect(ctx.destination);
    oscs.push(osc);

    osc.start(noteStart);
    osc.stop(decay + 0.05);

    if (isLast) {
      osc.onended = () => {
        oscs.forEach(o => { try { o.disconnect(); } catch {} });
        opts.onEnd?.();
      };
    }
  });

  return { stop: () => oscs.forEach(o => { try { o.stop(); } catch {} }) };
};

export const softPack: GeneratedSoundPack = {
  ...generateSoundPack(SOFT_INSTRUMENT),
  "hero.complete": softHeroComplete,
  "hero.milestone": softHeroMilestone,
};

// ---------------------------------------------------------------------------
// Aero Pack - Ethereal, breathy hero sounds with shimmer
// ---------------------------------------------------------------------------

const aeroHeroComplete: SoundSynthesizer = (ctx: AudioContext, opts: PlaySoundOptions): SoundPlayback => {
  const t = ctx.currentTime;
  const vol = (opts.volume ?? 1) * 0.7;
  // Open-sky ascending 4ths and 5ths
  const notes = [NOTES.D4, NOTES.G4, NOTES.A4, NOTES.D5, NOTES.G5];
  const oscs: OscillatorNode[] = [];

  notes.forEach((freq, i) => {
    const noteStart = t + i * 0.18;
    const isLast = i === notes.length - 1;
    const decay = noteStart + 0.15 + (isLast ? 0.5 : 0.08);

    // Main tone
    const osc = ctx.createOscillator();
    osc.type = "sine";
    osc.frequency.value = freq;

    // Shimmer octave
    const osc2 = ctx.createOscillator();
    osc2.type = "sine";
    osc2.frequency.value = freq * 2.003;

    const g = ctx.createGain();
    g.gain.setValueAtTime(0.001, noteStart);
    g.gain.linearRampToValueAtTime(vol, noteStart + 0.015);
    g.gain.exponentialRampToValueAtTime(0.001, decay);

    const g2 = ctx.createGain();
    g2.gain.setValueAtTime(0.001, noteStart);
    g2.gain.linearRampToValueAtTime(vol * 0.25, noteStart + 0.015);
    g2.gain.exponentialRampToValueAtTime(0.001, decay);

    osc.connect(g); g.connect(ctx.destination);
    osc2.connect(g2); g2.connect(ctx.destination);
    oscs.push(osc, osc2);

    osc.start(noteStart); osc.stop(decay + 0.05);
    osc2.start(noteStart); osc2.stop(decay + 0.05);

    if (isLast) {
      osc.onended = () => {
        oscs.forEach(o => { try { o.disconnect(); } catch {} });
        opts.onEnd?.();
      };
    }
  });

  return { stop: () => oscs.forEach(o => { try { o.stop(); } catch {} }) };
};

